using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Reflection;
using AdofaiTweaks.Core;
using AdofaiTweaks.Core.Attributes;
using AdofaiTweaks.Strings;
using AdofaiTweaks.Translation;
using HarmonyLib;
using UnityEngine;
using UnityModManagerNet;

namespace AdofaiTweaks;

public static class AdofaiTweaks
{
    public static UnityModManager.ModEntry.ModLogger Logger { get; private set; }
    public static bool IsEnabled { get; private set; }
    public static readonly int ReleaseNumber = (int)AccessTools.Field(typeof(GCNS), "releaseNumber").GetValue(null);

    [SyncTweakSettings]
    public static GlobalSettings GlobalSettings { get; set; }

    private static List<Type> allTweakTypes;
    private static readonly List<TweakRunner> tweakRunners = new List<TweakRunner>();
    private static SettingsSynchronizer synchronizer;

    internal static void Setup(UnityModManager.ModEntry modEntry) {
        allTweakTypes =
            AppDomain.CurrentDomain.GetAssemblies()
                .SelectMany(a => a.GetTypes())
                .Where(t => t.GetCustomAttribute<RegisterTweakAttribute>() != null)
                .OrderBy(t => t.Name)
                .ThenBy(t => t.GetCustomAttribute<RegisterTweakAttribute>().Priority)
                .ToList();

        Logger = modEntry.Logger;
        synchronizer = new SettingsSynchronizer();
        synchronizer.Load(modEntry);

        synchronizer.Register(typeof(TweakStrings));
        synchronizer.Register(typeof(AdofaiTweaks));
        synchronizer.Register(typeof(TweakRunner));

        modEntry.OnToggle = OnToggle;
        modEntry.OnGUI = OnGUI;
        modEntry.OnHideGUI = OnHideGUI;
        modEntry.OnSaveGUI = OnSaveGUI;
        modEntry.OnUpdate = OnUpdate;

#if DEBUG
        modEntry.HasUpdate = false;
        modEntry.Info.DisplayName += " <color=#a7a7a7><i>[Debug Build]</i></color>";
#endif
    }

    private static bool OnToggle(UnityModManager.ModEntry modEntry, bool value) {
        IsEnabled = value;
        if (value) {
            StartTweaks();
        } else {
            StopTweaks();
            synchronizer.Save(modEntry);
        }
        return true;
    }

    private static void StartTweaks() {
        HashSet<string> tweakIds = new HashSet<string>();
        foreach (Type tweakType in allTweakTypes) {
            RegisterTweakAttribute registerAttribute = tweakType.GetCustomAttribute<RegisterTweakAttribute>();
            if (tweakIds.Contains(registerAttribute.Id)) {
                throw new InvalidOperationException("Found conflicting tweaks with the ID '{0}', ");
            }
            ConstructorInfo constructor = tweakType.GetConstructor(new Type[] { });
            Tweak tweak = (Tweak)constructor.Invoke(null);
            TweakSettings settings = synchronizer.GetSettingsForType(registerAttribute.SettingsType);
            TweakRunner runner = new TweakRunner(tweak, settings);
            tweakRunners.Add(runner);
            synchronizer.Register(runner.Tweak);
            synchronizer.Register(runner.TweakMetadata.PatchesType);
        }
        synchronizer.Sync();
        foreach (TweakRunner runner in tweakRunners) {
            runner.Start();
        }
    }

    private static void StopTweaks() {
        foreach (TweakRunner runner in tweakRunners) {
            runner.Stop();
            synchronizer.Unregister(runner.Tweak);
            synchronizer.Unregister(runner.TweakMetadata.PatchesType);
        }
        tweakRunners.Clear();
    }

    private static void OnGUI(UnityModManager.ModEntry modEntry) {
        if (GlobalSettings.Language.IsSymbolLanguage() && TweakAssets.SymbolLangNormalFont != null) {
            GUI.skin.button.font = TweakAssets.SymbolLangNormalFont;
            GUI.skin.label.font = TweakAssets.SymbolLangNormalFont;
            GUI.skin.textArea.font = TweakAssets.SymbolLangNormalFont;
            GUI.skin.textField.font = TweakAssets.SymbolLangNormalFont;
            GUI.skin.toggle.font = TweakAssets.SymbolLangNormalFont;
            GUI.skin.button.fontSize = 15;
            GUI.skin.label.fontSize = 15;
            GUI.skin.textArea.fontSize = 15;
            GUI.skin.textField.fontSize = 15;
            GUI.skin.toggle.fontSize = 15;
        }
        GUI.skin.toggle = new GUIStyle(GUI.skin.toggle) {
            margin = new RectOffset(0, 4, 6, 6),
        };
        GUI.skin.label.wordWrap = false;

        GUILayout.Space(4);

        GUILayout.BeginHorizontal();
        GUILayout.Space(4);
        GUILayout.Label(
            TweakStrings.Get(TranslationKeys.Global.GLOBAL_LANGUAGE),
            new GUIStyle(GUI.skin.label) {
                fontStyle = GlobalSettings.Language.IsSymbolLanguage() ? FontStyle.Normal : FontStyle.Bold,
                font = GlobalSettings.Language.IsSymbolLanguage() ? TweakAssets.KoreanBoldFont : null,
            });
        foreach (LanguageEnum language in Enum.GetValues(typeof(LanguageEnum))) {
            string langString = TweakStrings.GetForLanguage(TranslationKeys.Global.LANGUAGE_NAME, language);
            GUIStyle style = new GUIStyle(GUI.skin.button);
            if (language == GlobalSettings.Language) {
                if (language.IsSymbolLanguage() && TweakAssets.KoreanBoldFont != null) {
                    style.font = TweakAssets.KoreanBoldFont;
                    style.fontSize = 15;
                } else if (!language.IsSymbolLanguage()) {
                    style.fontStyle = FontStyle.Bold;
                }
            } else if (language.IsSymbolLanguage() && TweakAssets.SymbolLangNormalFont != null) {
                style.font = TweakAssets.SymbolLangNormalFont;
                style.fontSize = 15;
            }
            bool click = GUILayout.Button(langString, style);
            if (click) {
                GlobalSettings.Language = language;
                foreach (TweakRunner runner in tweakRunners) {
                    runner.OnLanguageChange();
                }
            }
        }
        GUILayout.FlexibleSpace();
        GUILayout.EndHorizontal();

        GUILayout.Space(4);
        foreach (TweakRunner runner in tweakRunners) {
            runner.OnGUI();
        }

        GUI.skin.button.font = null;
        GUI.skin.label.font = null;
        GUI.skin.textArea.font = null;
        GUI.skin.textField.font = null;
        GUI.skin.toggle.font = null;
        GUI.skin.button.fontSize = 0;
        GUI.skin.label.fontSize = 0;
        GUI.skin.textArea.fontSize = 0;
        GUI.skin.textField.fontSize = 0;
        GUI.skin.toggle.fontSize = 0;

        GUILayout.FlexibleSpace();
        GUILayout.BeginHorizontal();
        GUILayout.FlexibleSpace();
        var footerStyle = new GUIStyle(GUI.skin.label) { fontSize = 10, fontStyle = FontStyle.Italic };
        footerStyle.normal.textColor = new Color(0.45f, 0.45f, 0.45f, 1f);
        GUILayout.Label(GetFooterText(), footerStyle);
        GUILayout.FlexibleSpace();
        GUILayout.EndHorizontal();

#if DEBUG
        GUILayout.Label($"<color=#a7a7a7><i>DEBUG: r{ReleaseNumber}</i></color>");
#endif
    }

    private static void OnHideGUI(UnityModManager.ModEntry modEntry) {
        foreach (TweakRunner runner in tweakRunners) {
            runner.OnHideGUI();
        }
        synchronizer.Save(modEntry);
    }

    private static void OnSaveGUI(UnityModManager.ModEntry modEntry) {
        synchronizer.Save(modEntry);
    }

    private static void OnUpdate(UnityModManager.ModEntry modEntry, float deltaTime) {
        foreach (TweakRunner runner in tweakRunners) {
            runner.OnUpdate(deltaTime);
        }
    }

    private static string GetFooterText() {
        switch (GlobalSettings.Language.ToString()) {
            case "CHINESE_SIMPLIFIED":
                return "原版模组作者 PizzaLovers007 | Unity 6 移植 @Trusler | 可能存在未知 Bug";
            case "KOREAN":
                return "원본 모드 제작자 PizzaLovers007 | Unity 6 포팅 @Trusler | 알 수 없는 버그가 있을 수 있습니다";
            case "JAPANESE":
                return "原作 PizzaLovers007 | Unity 6 移植 @Trusler | 未知のバグが存在する可能性があります";
            default:
                return "Original mod by PizzaLovers007 | Unity 6 port by @Trusler | Unknown bugs may exist";
        }
    }
}

namespace AdofaiTweaks;

public static class GameVersionState {
    static GameVersionState() {
        OldAsyncInputAvailable = AdofaiTweaks.ReleaseNumber == 97;
        AsyncInputAvailable = AdofaiTweaks.ReleaseNumber >= 98;
    }

    public static readonly bool OldAsyncInputAvailable;
    public static readonly bool AsyncInputAvailable;
}

using AdofaiTweaks.Core;
using AdofaiTweaks.Translation;

namespace AdofaiTweaks;

/// <summary>
/// The global settings for AdofaiTweaks.
/// </summary>
public class GlobalSettings : TweakSettings
{
    /// <summary>
    /// The current language for the user.
    /// </summary>
    public LanguageEnum Language { get; set; } = LanguageEnum.ENGLISH;
}

using System;
using System.IO;
using UnityModManagerNet;

namespace AdofaiTweaks;

internal static class Startup
{
    internal static void Load(UnityModManager.ModEntry modEntry) {
        LoadAssembly("Mods/AdofaiTweaks/AdofaiTweaks.Strings.dll");
        LoadAssembly("Mods/AdofaiTweaks/AdofaiTweaks.Translation.dll");
        LoadAssembly("Mods/AdofaiTweaks/LiteDB.dll");
        LoadAssembly("Mods/AdofaiTweaks/System.Buffers.dll");
        LoadAssembly("Mods/AdofaiTweaks/IndexRange.dll");

        if (TryLoadAssembly("A Dance of Fire and Ice_Data/Managed/SkyHook.Unity.dll")) {
            LoadAssembly("Mods/AdofaiTweaks/AdofaiTweaks.Compat.AsyncSkyHook.dll");
            modEntry.Logger.Log("Async assembly: SkyHook");
        } else if (TryLoadAssembly("A Dance of Fire and Ice_Data/Managed/SharpHook.dll")) {
            LoadAssembly("Mods/AdofaiTweaks/AdofaiTweaks.Compat.AsyncSharpHook.dll");
            modEntry.Logger.Log("Async assembly: SharpHook");
        } else {
            LoadAssembly("Mods/AdofaiTweaks/AdofaiTweaks.Compat.AsyncPolyfill.dll");
            modEntry.Logger.Log("Async assembly: Polyfill");
        }

        AdofaiTweaks.Setup(modEntry);
    }

    private static void LoadAssembly(string path) {
        using FileStream stream = new FileStream(path, FileMode.Open);
        byte[] data = new byte[stream.Length];
        stream.Read(data, 0, data.Length);
        AppDomain.CurrentDomain.Load(data);
    }

    private static bool TryLoadAssembly(string path) {
        try {
            LoadAssembly(path);
            return true;
        } catch (Exception) {
            return false;
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace AdofaiTweaks.Core;

/// <summary>
/// Additional <see cref="GUILayout"/> components.
/// </summary>
public static class MoreGUILayout
{
    /// <summary>
    /// Begins an indented section with a given indentation size.
    /// </summary>
    /// <param name="indentSize">The size of the indentation.</param>
    public static void BeginIndent(float indentSize = 20f) {
        GUILayout.BeginHorizontal();
        GUILayout.Space(indentSize);
        GUILayout.BeginVertical();
    }

    /// <summary>
    /// Ends an indented section.
    /// </summary>
    public static void EndIndent() {
        GUILayout.EndVertical();
        GUILayout.EndHorizontal();
    }

    /// <summary>
    /// Displays RGB sliders for the given color.
    /// </summary>
    /// <param name="color">The color to set the sliders to.</param>
    /// <returns>The resulting color from any changed sliders.</returns>
    public static Color ColorRgbSliders(Color color) {
        float oldR = Mathf.Round(color.r * 255);
        float oldG = Mathf.Round(color.g * 255);
        float oldB = Mathf.Round(color.b * 255);
        float newR = NamedSlider("R:", oldR, 0, 255, 300f, 1, 40f);
        float newG = NamedSlider("G:", oldG, 0, 255, 300f, 1, 40f);
        float newB = NamedSlider("B:", oldB, 0, 255, 300f, 1, 40f);
        if (oldR != newR || oldG != newG || oldB != newB) {
            return new Color(newR / 255, newG / 255, newB / 255);
        }
        return color;
    }

    /// <summary>
    /// Displays RGBA sliders for the given color.
    /// </summary>
    /// <param name="color">The color to set the sliders to.</param>
    /// <returns>The resulting color from any changed sliders.</returns>
    public static Color ColorRgbaSliders(Color color) {
        float oldR = Mathf.Round(color.r * 255);
        float oldG = Mathf.Round(color.g * 255);
        float oldB = Mathf.Round(color.b * 255);
        float oldA = Mathf.Round(color.a * 255);
        float newR = NamedSlider("R:", oldR, 0, 255, 300f, 1, 40f);
        float newG = NamedSlider("G:", oldG, 0, 255, 300f, 1, 40f);
        float newB = NamedSlider("B:", oldB, 0, 255, 300f, 1, 40f);
        float newA = NamedSlider("A:", oldA, 0, 255, 300f, 1, 40f);
        if (oldR != newR || oldG != newG || oldB != newB || oldA != newA) {
            return new Color(newR / 255, newG / 255, newB / 255, newA / 255);
        }
        return color;
    }

    /// <summary>
    /// Displays two RGB sliders for two different colors horizontally
    /// adjacent to each other.
    /// </summary>
    /// <param name="color1">The left color to set the sliders to.</param>
    /// <param name="color2">The right color to set the sliders to.</param>
    /// <returns>
    /// The resulting colors pair from any changed sliders.
    /// </returns>
    public static (Color, Color) ColorRgbSlidersPair(Color color1, Color color2) {
        float oldR1 = Mathf.Round(color1.r * 255);
        float oldG1 = Mathf.Round(color1.g * 255);
        float oldB1 = Mathf.Round(color1.b * 255);
        float oldR2 = Mathf.Round(color2.r * 255);
        float oldG2 = Mathf.Round(color2.g * 255);
        float oldB2 = Mathf.Round(color2.b * 255);
        var (newR1, newR2) = NamedSliderPair("R:", "R:", oldR1, oldR2, 0, 255, 300f, 1, 40f);
        var (newG1, newG2) = NamedSliderPair("G:", "G:", oldG1, oldG2, 0, 255, 300f, 1, 40f);
        var (newB1, newB2) = NamedSliderPair("B:", "B:", oldB1, oldB2, 0, 255, 300f, 1, 40f);
        if (oldR1 != newR1 || oldG1 != newG1 || oldB1 != newB1) {
            color1 = new Color(newR1 / 255, newG1 / 255, newB1 / 255);
        }
        if (oldR2 != newR2 || oldG2 != newG2 || oldB2 != newB2) {
            color2 = new Color(newR2 / 255, newG2 / 255, newB2 / 255);
        }
        return (color1, color2);
    }

    /// <summary>
    /// Displays two RGBA sliders for two different colors horizontally
    /// adjacent to each other.
    /// </summary>
    /// <param name="color1">The left color to set the sliders to.</param>
    /// <param name="color2">The right color to set the sliders to.</param>
    /// <returns>
    /// The resulting colors pair from any changed sliders.
    /// </returns>
    public static (Color, Color) ColorRgbaSlidersPair(Color color1, Color color2) {
        float oldR1 = Mathf.Round(color1.r * 255);
        float oldG1 = Mathf.Round(color1.g * 255);
        float oldB1 = Mathf.Round(color1.b * 255);
        float oldA1 = Mathf.Round(color1.a * 255);
        float oldR2 = Mathf.Round(color2.r * 255);
        float oldG2 = Mathf.Round(color2.g * 255);
        float oldB2 = Mathf.Round(color2.b * 255);
        float oldA2 = Mathf.Round(color2.a * 255);
        var (newR1, newR2) = NamedSliderPair("R:", "R:", oldR1, oldR2, 0, 255, 300f, 1, 40f);
        var (newG1, newG2) = NamedSliderPair("G:", "G:", oldG1, oldG2, 0, 255, 300f, 1, 40f);
        var (newB1, newB2) = NamedSliderPair("B:", "B:", oldB1, oldB2, 0, 255, 300f, 1, 40f);
        var (newA1, newA2) = NamedSliderPair("A:", "A:", oldA1, oldA2, 0, 255, 300f, 1, 40f);
        if (oldR1 != newR1 || oldG1 != newG1 || oldB1 != newB1 || oldA1 != newA1) {
            color1 = new Color(newR1 / 255, newG1 / 255, newB1 / 255, newA1 / 255);
        }
        if (oldR2 != newR2 || oldG2 != newG2 || oldB2 != newB2 || oldA2 != newA2) {
            color2 = new Color(newR2 / 255, newG2 / 255, newB2 / 255, newA2 / 255);
        }
        return (color1, color2);
    }

    /// <summary>
    /// Displays a slider with a name on the left and its value on the
    /// right.
    /// </summary>
    /// <param name="name">The name to show on the left.</param>
    /// <param name="value">The value of the slider.</param>
    /// <param name="leftValue">The minimum value for the slider.</param>
    /// <param name="rightValue">The maximum value for the slider.</param>
    /// <param name="sliderWidth">The width of the slider.</param>
    /// <param name="roundNearest">
    /// The fraction to round the value to. By default will result in no
    /// rounding.
    /// </param>
    /// <param name="labelWidth">
    /// The width of the name label on the left. By default will expand to
    /// fit the name's width.
    /// </param>
    /// <param name="valueFormat">
    /// The formatting for the value label on the right. By default will
    /// simply show the value.
    /// </param>
    /// <returns>The resulting value from any change in the slider.</returns>
    public static float NamedSlider(
        string name,
        float value,
        float leftValue,
        float rightValue,
        float sliderWidth,
        float roundNearest = 0,
        float labelWidth = 0,
        string valueFormat = "{0}") {
        GUILayout.BeginHorizontal();
        float newValue =
            NamedSliderContent(
                name,
                value,
                leftValue,
                rightValue,
                sliderWidth,
                roundNearest,
                labelWidth,
                valueFormat);
        GUILayout.EndHorizontal();
        return newValue;
    }

    /// <summary>
    /// Displays a two sliders that are horizontally adjacent with their
    /// names on the left and their values on the right.
    /// </summary>
    /// <param name="name1">
    /// The name for the left slider to show on the left.
    /// </param>
    /// <param name="name2">
    /// The name for the right slider to show on the left.
    /// </param>
    /// <param name="value1">The value of the left slider.</param>
    /// <param name="value2">The value of the right slider.</param>
    /// <param name="leftValue">The minimum value for the slider.</param>
    /// <param name="rightValue">The maximum value for the slider.</param>
    /// <param name="sliderWidth">The width of the slider.</param>
    /// <param name="roundNearest">
    /// The fraction to round the value to. By default will result in no
    /// rounding.
    /// </param>
    /// <param name="labelWidth">
    /// The width of the name label on the left. By default will expand to
    /// fit the name's width.
    /// </param>
    /// <param name="valueFormat">
    /// The formatting for the value label on the right. By default will
    /// simply show the value.
    /// </param>
    /// <returns>
    /// The resulting values pair from any change in the sliders.
    /// </returns>
    public static (float, float) NamedSliderPair(
        string name1,
        string name2,
        float value1,
        float value2,
        float leftValue,
        float rightValue,
        float sliderWidth,
        float roundNearest = 0,
        float labelWidth = 0,
        string valueFormat = "{0}") {
        GUILayout.BeginHorizontal();
        float newValue1 =
            NamedSliderContent(
                name1,
                value1,
                leftValue,
                rightValue,
                sliderWidth,
                roundNearest,
                labelWidth,
                valueFormat);
        float newValue2 =
            NamedSliderContent(
                name2,
                value2,
                leftValue,
                rightValue,
                sliderWidth,
                roundNearest,
                labelWidth,
                valueFormat);
        GUILayout.EndHorizontal();
        return (newValue1, newValue2);
    }

    private static float NamedSliderContent(
        string name,
        float value,
        float leftValue,
        float rightValue,
        float sliderWidth,
        float roundNearest = 0,
        float labelWidth = 0,
        string valueFormat = "{0}") {
        if (labelWidth == 0) {
            GUILayout.Label(name);
            GUILayout.Space(4f);
        } else {
            GUILayout.Label(name, GUILayout.Width(labelWidth));
        }
        float newValue =
            GUILayout.HorizontalSlider(
                value, leftValue, rightValue, GUILayout.Width(sliderWidth));
        if (roundNearest != 0) {
            newValue = Mathf.Round(newValue / roundNearest) * roundNearest;
        }
        GUILayout.Space(8f);
        GUILayout.Label(string.Format(valueFormat, newValue), GUILayout.Width(40f));
        GUILayout.FlexibleSpace();
        return newValue;
    }

    /// <summary>
    /// Displays a text field with a name on the left.
    /// </summary>
    /// <param name="name">The name to show on the left.</param>
    /// <param name="value">The value of the text field.</param>
    /// <param name="fieldWidth">The width of the text field.</param>
    /// <param name="labelWidth">
    /// The width of the name label on the left. By default will expand to
    /// fit the name's width.
    /// </param>
    /// <returns>
    /// The resulting value of the text field from any changes.
    /// </returns>
    public static string NamedTextField(
        string name,
        string value,
        float fieldWidth,
        float labelWidth = 0) {
        GUILayout.BeginHorizontal();
        string newValue = NamedTextFieldContent(name, value, fieldWidth, labelWidth);
        GUILayout.EndHorizontal();
        return newValue;
    }

    /// <summary>
    /// Displays two text fields that are horizontally adjacent with their
    /// names on the left.
    /// </summary>
    /// <param name="name1">
    /// The name of the left text field to show on the left.
    /// </param>
    /// <param name="name2">
    /// The name of the right text field to show on the left.
    /// </param>
    /// <param name="value1">The value of the left text field.</param>
    /// <param name="value2">The value of the right text field.</param>
    /// <param name="fieldWidth">The width of the text field.</param>
    /// <param name="labelWidth">
    /// The width of the name label on the left. By default will expand to
    /// fit the name's width.
    /// </param>
    /// <returns>
    /// The resulting values pair from any change in the text fields.
    /// </returns>
    public static (string, string) NamedTextFieldPair(
        string name1,
        string name2,
        string value1,
        string value2,
        float fieldWidth,
        float labelWidth = 0) {
        GUILayout.BeginHorizontal();
        string newValue1 = NamedTextFieldContent(name1, value1, fieldWidth, labelWidth);
        string newValue2 = NamedTextFieldContent(name2, value2, fieldWidth, labelWidth);
        GUILayout.EndHorizontal();
        return (newValue1, newValue2);
    }

    private static string NamedTextFieldContent(
        string name,
        string value,
        float fieldWidth,
        float labelWidth = 0) {
        if (labelWidth == 0) {
            GUILayout.Label(name);
            GUILayout.Space(4f);
        } else {
            GUILayout.Label(name, GUILayout.Width(labelWidth));
        }
        string newValue = GUILayout.TextField(value, GUILayout.Width(fieldWidth));
        GUILayout.FlexibleSpace();
        return newValue;
    }

    /// <summary>
    /// Displays two labels that are horizontally adjacent.
    /// </summary>
    /// <param name="text1">The text for the left label.</param>
    /// <param name="text2">The text for the right label.</param>
    /// <param name="textWidth">
    /// The width of the texts. By default will expand to fit the text's
    /// width.
    /// </param>
    public static void LabelPair(string text1, string text2, float textWidth = 0) {
        GUILayout.BeginHorizontal();
        if (textWidth == 0) {
            GUILayout.Label(text1);
            GUILayout.Space(4f);
        } else {
            GUILayout.Label(text1, GUILayout.Width(textWidth));
        }
        GUILayout.FlexibleSpace();
        GUILayout.Space(8f);
        if (textWidth == 0) {
            GUILayout.Label(text2);
            GUILayout.Space(4f);
        } else {
            GUILayout.Label(text2, GUILayout.Width(textWidth));
        }
        GUILayout.FlexibleSpace();
        GUILayout.Space(20f);
        GUILayout.EndHorizontal();
    }

    /// <summary>
    /// Displays a generic list of items where only one can be selected. The
    /// lists can be reordered via up and down buttons to the left of the
    /// items.
    /// </summary>
    /// <typeparam name="T">The object type to display.</typeparam>
    /// <param name="list">The list of generic objects to display.</param>
    /// <param name="selectedIndex">
    /// The currently selected index. If set to any value outside of the
    /// range of the list, no items will appear as selected.
    /// </param>
    /// <param name="nameFunc">
    /// The function determining what gets displayed for each object of type
    /// <see cref="T"/>.
    /// </param>
    /// <returns><c>true</c> if the selected item changed.</returns>
    public static bool ToggleList<T>(List<T> list, ref int selectedIndex, Func<T, string> nameFunc) {
        bool changed = false;
        int moveUp = -1, moveDown = -1;
        for (int i = 0; i < list.Count; i++) {
            T curr = list[i];
            string name = nameFunc.Invoke(curr);
            GUILayout.BeginHorizontal();

            // Move up/down
            GUILayout.BeginHorizontal();
            if (GUILayout.Button("▲") && i > 0) {
                moveUp = i;
            }
            if (GUILayout.Button("▼") && i < list.Count - 1) {
                moveDown = i;
            }
            GUILayout.EndHorizontal();

            GUILayout.Space(8f);

            if (GUILayout.Toggle(selectedIndex == i, name) && selectedIndex != i) {
                selectedIndex = i;
                changed = true;
            }
            GUILayout.FlexibleSpace();

            GUILayout.EndHorizontal();
        }
        if (moveUp != -1) {
            changed = true;
            (list[moveUp], list[moveUp - 1]) = (list[moveUp - 1], list[moveUp]);
            if (moveUp - 1 == selectedIndex) {
                selectedIndex++;
            } else if (moveUp == selectedIndex) {
                selectedIndex--;
            }
        } else if (moveDown != -1) {
            changed = true;
            (list[moveDown], list[moveDown + 1]) = (list[moveDown + 1], list[moveDown]);
            if (moveDown + 1 == selectedIndex) {
                selectedIndex--;
            } else if (moveDown == selectedIndex) {
                selectedIndex++;
            }
        }

        return changed;
    }

    /// <summary>
    /// Displays a horizontal line.
    /// </summary>
    /// <param name="thickness">The thickness of the line.</param>
    /// <param name="length">
    /// The length of the line. By default expands to take the remaining
    /// width of the GUI.
    /// </param>
    public static void HorizontalLine(float thickness, float length = 0f) {
        GUILayout.Box(GUIContent.none, new GUIStyle() {
            margin = new RectOffset(8, 8, 4, 4),
            padding = new RectOffset(),
            fixedHeight = thickness,
            fixedWidth = length,
            normal = {
                background = Texture2D.whiteTexture,
            },
        });
    }
}

using System;
using System.Collections.Generic;
using System.Reflection;
using System.Text;
using AdofaiTweaks.Core.Attributes;
using HarmonyLib;
using UnityModManagerNet;

namespace AdofaiTweaks.Core;

/// <summary>
/// This class helps synchronize <see cref="TweakSettings"/> properties
/// across the entire codebase. Two things must be done for the synchronizer
/// to inject the settings:
/// <list type="number">
/// <item>
/// The class type (or an instance of it) that has the
/// <see cref="TweakSettings"/> property must be registered to the
/// synchronizer via <see cref="Register(Type)"/> (or
/// <see cref="Register(object)"/> for the instance).
/// </item>
/// <item>
/// The <see cref="TweakSettings"/> property in the class must have the
/// <see cref="SyncTweakSettingsAttribute"/> attribute.
/// </item>
/// </list>
/// </summary>
internal class SettingsSynchronizer
{
    private readonly IDictionary<Type, TweakSettings> tweakSettingsDictionary =
        new Dictionary<Type, TweakSettings>();

    private readonly IDictionary<Type, object> registeredObjects =
        new Dictionary<Type, object>();

    /// <summary>
    /// Loads an instance of every <see cref="TweakSettings"/> type from the
    /// saved settings files.
    /// </summary>
    /// <param name="modEntry">The UMM mod entry for AdofaiTweaks.</param>
    public void Load(UnityModManager.ModEntry modEntry) {
        tweakSettingsDictionary.Clear();
        MethodInfo loadMethod =
            typeof(UnityModManager.ModSettings).GetMethod(
                nameof(UnityModManager.ModSettings.Load),
                AccessTools.all,
                null,
                new Type[] { typeof(UnityModManager.ModEntry) },
                null);
        foreach (Type type in Assembly.GetExecutingAssembly().GetTypes()) {
            if (!type.IsSubclassOf(typeof(TweakSettings))) {
                continue;
            }
            modEntry.Logger.Log($"Loading: {type.FullName}");
            MethodInfo genericLoadMethod = loadMethod.MakeGenericMethod(type);
            try {
                tweakSettingsDictionary[type] =
                    (TweakSettings)genericLoadMethod.Invoke(
                        null, new object[] { modEntry });
            } catch (Exception e) {
                AdofaiTweaks.Logger.Error(
                    $"Failed to read settings for {type.FullName}: {e}.");
                ConstructorInfo constructor = type.GetConstructor(null);
                tweakSettingsDictionary[type] =
                    (TweakSettings)constructor.Invoke(null);
            }
        }
    }

    /// <summary>
    /// Saves every <see cref="TweakSettings"/> instance to their respective
    /// files.
    /// </summary>
    /// <param name="modEntry">The UMM mod entry for AdofaiTweaks.</param>
    public void Save(UnityModManager.ModEntry modEntry) {
        foreach (Type type in tweakSettingsDictionary.Keys) {
            modEntry.Logger.Log("Saving: " + type.FullName);
            tweakSettingsDictionary[type].Save(modEntry);
        }
    }

    /// <summary>
    /// Injects the loaded <see cref="TweakSettings"/> instances into all
    /// the registered types/objects.
    /// </summary>
    public void Sync() {
        foreach (Type type in registeredObjects.Keys) {
            ApplySettingsTo(type, registeredObjects[type]);
        }
    }

    /// <summary>
    /// Gets the <see cref="TweakSettings"/> instance for the given
    /// <see cref="Tweak"/> type.
    /// </summary>
    /// <param name="tweakType">The type of the tweak.</param>
    /// <returns>
    /// The <see cref="TweakSettings"/> instance for the given
    /// <see cref="Tweak"/> type.
    /// </returns>
    public TweakSettings GetSettingsForType(Type tweakType) {
        return tweakSettingsDictionary[tweakType];
    }

    /// <summary>
    /// Registers the given type to the synchronizer.
    /// </summary>
    /// <param name="type">The type to register.</param>
    /// <exception cref="ArgumentException">
    /// Thrown when the type is already registered.
    /// </exception>
    public void Register(Type type) {
        Register(type, null);
    }

    /// <summary>
    /// Registers the given object to the synchronizer.
    /// </summary>
    /// <param name="obj">The object to register.</param>
    /// <exception cref="ArgumentException">
    /// Thrown when another object of this type is already registered.
    /// </exception>
    public void Register(object obj) {
        Register(obj.GetType(), obj);
    }

    private void Register(Type type, object obj) {
        if (registeredObjects.ContainsKey(type)) {
            throw new ArgumentException(
                string.Format(
                    "An object of type {0} has already been registered to " +
                    "SettingsSynchronizer. Please only register one object of every type to " +
                    "the synchronizer.",
                    type.FullName));
        }
        registeredObjects[type] = obj;
    }

    /// <summary>
    /// Unregisters the given type from the synchronizer.
    /// </summary>
    /// <param name="type">The type to unregister.</param>
    /// <exception cref="ArgumentException">
    /// Thrown when the type is not registered.
    /// </exception>
    public void Unregister(Type type) {
        Unregister(type, null);
    }

    /// <summary>
    /// Unregisters the given object from the synchronizer.
    /// </summary>
    /// <param name="obj">The object to unregister.</param>
    /// <exception cref="ArgumentException">
    /// Thrown when the object is not registered.
    /// </exception>
    public void Unregister(object obj) {
        Unregister(obj.GetType(), obj);
    }

    private void Unregister(Type type, object obj) {
        if (!registeredObjects.ContainsKey(type)) {
            throw new ArgumentException(
                $"No object of type {type.FullName} is registered in SettingsSynchronizer. This is " +
                "most likely due to a misconfiguration. Please ensure you are " +
                "registering the object correctly.");
        }
        if (registeredObjects[type] != obj) {
            throw new ArgumentException(
                $"The registered object of type {type.FullName} differs from the object trying to be " +
                "unregistered. Please ensure you are unregistering the correct object.");
        }
        registeredObjects.Remove(type);
    }

    private void ApplySettingsTo(Type type, object obj = null) {
        foreach (PropertyInfo prop in type.GetProperties(AccessTools.all)) {
            if (prop.GetCustomAttribute<SyncTweakSettingsAttribute>() == null) {
                continue;
            }
            try {
                prop.SetValue(obj, tweakSettingsDictionary[prop.GetUnderlyingType()]);
            } catch (Exception e) {
                AdofaiTweaks.Logger.Error(GenerateMessage(type, obj, prop, e));
            }
        }
    }

    private string GenerateMessage(
        Type patchType, object obj, PropertyInfo tweakProp, Exception e) {
        var sb = new StringBuilder();
        sb.AppendFormat(
            "Unable to update property {0} in object {1} (type is {2}).\n",
            tweakProp.Name,
            obj,
            patchType.FullName);
        sb.AppendFormat("Exception: {0}", e);
        return sb.ToString();
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace AdofaiTweaks.Core;

/// <summary>
/// A simple <see cref="UnityEngine.UI.Text"/> wrapper that has a drop
/// shadow.
/// </summary>
public class ShadowedText : MonoBehaviour
{
    private Text mainText;
    private Text shadowText;

    /// <summary>
    /// The text that this object displays.
    /// </summary>
    public string Text {
        get {
            return mainText.text;
        }
        set {
            mainText.text = value;
            shadowText.text = value;
        }
    }

    /// <summary>
    /// The alignment of the text.
    /// </summary>
    public TextAnchor Alignment {
        get {
            return mainText.alignment;
        }
        set {
            mainText.alignment = value;
            shadowText.alignment = value;
        }
    }

    /// <summary>
    /// The font size of the text.
    /// </summary>
    public int FontSize {
        get {
            return mainText.fontSize;
        }
        set {
            mainText.fontSize = value;
            shadowText.fontSize = value;
            shadowText.rectTransform.anchoredPosition =
                Position + new Vector2(value / 20f, -value / 20f);
        }
    }

    /// <summary>
    /// The color of the text.
    /// </summary>
    public Color Color {
        get {
            return mainText.color;
        }
        set {
            mainText.color = value;
        }
    }

    /// <summary>
    /// The normalized center position within the bounding box of the text.
    /// </summary>
    public Vector2 Center {
        get {
            return mainText.rectTransform.anchorMin;
        }
        set {
            mainText.rectTransform.anchorMin = value;
            mainText.rectTransform.anchorMax = value;
            mainText.rectTransform.pivot = value;
            shadowText.rectTransform.anchorMin = value;
            shadowText.rectTransform.anchorMax = value;
            shadowText.rectTransform.pivot = value;
        }
    }

    /// <summary>
    /// The position within the <see cref="Canvas"/> that the text is at.
    /// </summary>
    public Vector2 Position {
        get {
            return mainText.rectTransform.anchoredPosition;
        }
        set {
            mainText.rectTransform.anchoredPosition = value;
            shadowText.rectTransform.anchoredPosition =
                value + new Vector2(FontSize / 20f, -FontSize / 20f);
        }
    }

    /// <summary>
    /// Unity's Awake lifecycle event handler. Creates the text with a drop
    /// shadow.
    /// </summary>
    protected void Awake() {
        Canvas canvas = gameObject.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        CanvasScaler scaler = gameObject.AddComponent<CanvasScaler>();
        scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        scaler.referenceResolution = new Vector2(1920, 1080);

        ContentSizeFitter fitter;

        GameObject shadowObject = new GameObject();
        fitter = shadowObject.AddComponent<ContentSizeFitter>();
        fitter.verticalFit = ContentSizeFitter.FitMode.PreferredSize;
        fitter.horizontalFit = ContentSizeFitter.FitMode.PreferredSize;
        shadowObject.transform.SetParent(transform);
        shadowText = shadowObject.AddComponent<Text>();
        shadowText.font = RDString.GetFontDataForLanguage(RDString.language).font;
        shadowText.color = Color.black.WithAlpha(0.4f);

        GameObject mainObject = new GameObject();
        mainObject.transform.SetParent(transform);
        fitter = mainObject.AddComponent<ContentSizeFitter>();
        fitter.verticalFit = ContentSizeFitter.FitMode.PreferredSize;
        fitter.horizontalFit = ContentSizeFitter.FitMode.PreferredSize;
        mainText = mainObject.AddComponent<Text>();
        mainText.font = RDString.GetFontDataForLanguage(RDString.language).font;
    }
}

