using System;
using System.Collections.Generic;
using System.Xml.Serialization;
using AdofaiTweaks.Strings;
using UnityEngine;

namespace AdofaiTweaks.Core;

/// <summary>
/// A key shortcut you can check every frame.
/// </summary>
public class TweakKeyShortcut
{
    [NonSerialized]
    private readonly ISet<KeyCode> BLACKLISTED_KEYS = new HashSet<KeyCode>
    {
        KeyCode.LeftControl,
        KeyCode.LeftCommand,
        KeyCode.LeftApple,
        KeyCode.LeftShift,
        KeyCode.LeftAlt,
        KeyCode.RightControl,
        KeyCode.RightCommand,
        KeyCode.RightApple,
        KeyCode.RightShift,
        KeyCode.RightAlt,
        KeyCode.Mouse0,
        KeyCode.Mouse1,
        KeyCode.Mouse2,
        KeyCode.Mouse3,
        KeyCode.Mouse4,
        KeyCode.Mouse5,
        KeyCode.Mouse6,
    };

    /// <summary>
    /// Whether ctrl should be pressed to trigger this shortcut.
    /// </summary>
    public bool PressCtrl { get; set; }

    /// <summary>
    /// Whether shift should be pressed to trigger this shortcut.
    /// </summary>
    public bool PressShift { get; set; }

    /// <summary>
    /// Whether alt should be pressed to trigger this shortcut.
    /// </summary>
    public bool PressAlt { get; set; }

    /// <summary>
    /// Key that should be pressed to trigger this shortcut.
    /// </summary>
    public KeyCode PressKey { get; set; }

    /// <summary>
    /// Whether AdofaiTweaks is listening for key changes to the shortcut.
    /// </summary>
    [XmlIgnore]
    public bool IsListening { get; set; }

    /// <summary>
    /// Initializes a new instance of the <see cref="TweakKeyShortcut"/>
    /// class.
    /// </summary>
    public TweakKeyShortcut() { }

    /// <summary>
    /// Check if this shortcut is pressed in current frame. SHOULD BE ONLY
    /// CALLED IN <c>Update()</c>.
    /// </summary>
    /// <returns>Whether the shortcut is precisely triggered.</returns>
    public bool CheckShortcut() {
        bool holdingCtrl =
            Input.GetKey(KeyCode.LeftControl) || Input.GetKey(KeyCode.RightControl)
                                              || Input.GetKey(KeyCode.LeftMeta) || Input.GetKey(KeyCode.RightMeta);
        bool holdingShift =
            Input.GetKey(KeyCode.LeftShift) || Input.GetKey(KeyCode.RightShift);
        bool holdingAlt =
            Input.GetKey(KeyCode.LeftAlt) || Input.GetKey(KeyCode.RightAlt);

        return PressCtrl == holdingCtrl
               && PressShift == holdingShift
               && PressAlt == holdingAlt
               && Input.GetKeyDown(PressKey);
    }

    /// <summary>
    /// Visualize shortcut options. SHOULD BE ONLY CALLED IN <c>OnGUI()</c>.
    /// </summary>
    /// <param name="labelText">
    /// The label text that is shown before the shortcut GUI.
    /// </param>
    public void DrawShortcut(string labelText = null) {
        GUILayout.BeginHorizontal();

        if (!string.IsNullOrEmpty(labelText)) {
            GUILayout.Label(labelText);
            GUILayout.Space(8f);
        }

        // Control
        PressCtrl = GUILayout.Toggle(PressCtrl, "Control");
        GUILayout.Label(" + ");

        // Shift
        PressShift = GUILayout.Toggle(PressShift, "Shift");
        GUILayout.Label(" + ");

        // Alt
        PressAlt = GUILayout.Toggle(PressAlt, "Alt");
        GUILayout.Label(" + ");

        // Keycode
        var oldColor = GUI.color;
        if (IsListening) {
            GUI.color = new Color(1f, 0.5f, 0f); // orange
        }
        GUILayout.Box(PressKey.ToString());
        GUI.color = oldColor;
        string changeOrDoneText =
            TweakStrings.Get(IsListening
                ? TranslationKeys.Global.SHORTCUT_DONE
                : TranslationKeys.Global.SHORTCUT_CHANGE_KEY);
        GUILayout.Space(8f);
        if (GUILayout.Button(changeOrDoneText)) {
            IsListening = !IsListening;
        }

        if (IsListening) {
            foreach (KeyCode code in Enum.GetValues(typeof(KeyCode))) {
                // Skip key if not pressed or blacklisted
                if (!Input.GetKeyDown(code) || BLACKLISTED_KEYS.Contains(code)) {
                    continue;
                }

                // Change key
                PressKey = code;
                IsListening = false;
            }
        }

        GUILayout.FlexibleSpace();

        // Exit scope
        GUILayout.EndHorizontal();
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Reflection;
using AdofaiTweaks.Core.Attributes;
using HarmonyLib;

namespace AdofaiTweaks.Core;

internal class TweakPatch
{
    internal TweakPatch(Type patchType, TweakPatchAttribute metadata, Harmony harmony, Assembly assembly = null) {
        PatchType = patchType;
        Metadata = metadata;
        Harmony = harmony;
        ClassType = (assembly ?? typeof(ADOBase).Assembly).GetType(Metadata.ClassName);
        PatchTargetMethods = ClassType?.GetMethods(AccessTools.all).Where(m => m.Name.Equals(Metadata.MethodName));
    }

    private Harmony Harmony { get; }
    private Type ClassType { get; }
    private Type PatchType { get; }
    private IEnumerable<MethodInfo> PatchTargetMethods { get; }
    private readonly string[] _hardcodedMethodNames = ["Prefix", "Postfix", "Transpiler", "Finalizer"];

    internal TweakPatchAttribute Metadata { get; }
    internal bool IsEnabled { get; private set; }

    internal bool IsValidPatch(bool showDebuggingMessage = false) {
        if ((Metadata.MinVersion <= AdofaiTweaks.ReleaseNumber || Metadata.MinVersion == -1) &&
            (Metadata.MaxVersion >= AdofaiTweaks.ReleaseNumber || Metadata.MaxVersion == -1) &&
            ClassType != null &&
            PatchType != null &&
            (PatchTargetMethods?.Count() ?? 0) != 0) {
            return true;
        }

#if DEBUG
        if (showDebuggingMessage) {
            AdofaiTweaks.Logger.Log(
                string.Format(
                    "Patch {0} is inapplicable!\n" +
                    " ├ ClassType is {8} - Expected Not Null\n" +
                    " ├ PatchTargetMethods count is {10}{11} - Expected above 0\n" +
                    " └ Patch target method name is {12}",
                    Metadata.PatchId, Metadata.MinVersion, AdofaiTweaks.ReleaseNumber,
                    Metadata.MinVersion <= AdofaiTweaks.ReleaseNumber || Metadata.MinVersion == -1,
                    Metadata.MinVersion == -1 ? " (-1)" : "",
                    Metadata.MaxVersion,
                    Metadata.MaxVersion >= AdofaiTweaks.ReleaseNumber || Metadata.MaxVersion == -1,
                    Metadata.MaxVersion == -1 ? " (-1)" : "",
                    ClassType,
                    PatchType,
                    PatchTargetMethods?.Count() ?? 0,
                    PatchTargetMethods == null ? " (null)" : "",
                    Metadata.MethodName));
        }
#endif
        return false;
    }

    internal void Patch() {
        if (!IsEnabled) {
#if DEBUG
            AdofaiTweaks.Logger.Log($"Applying patch {Metadata.PatchId}");
#endif
            foreach (MethodInfo method in PatchTargetMethods) {
                if (method.IsAbstract) continue;
                List<HarmonyMethod> hardcodedMethods = new List<HarmonyMethod>();
                foreach (string methodName in _hardcodedMethodNames) {
                    MethodInfo patchMethod = AccessTools.Method(PatchType, methodName);
                    hardcodedMethods.Add(patchMethod == null ? null : new HarmonyMethod(patchMethod));
                }
                Harmony.Patch(method, hardcodedMethods[0], hardcodedMethods[1], hardcodedMethods[2], hardcodedMethods[3]);
            }
            IsEnabled = true;
        }
    }

    internal void Unpatch() {
        if (IsEnabled) {
#if DEBUG
            AdofaiTweaks.Logger.Log($"Cancelling patch {Metadata.PatchId}");
#endif
            foreach (MethodInfo original in PatchTargetMethods) {
                foreach (MethodInfo patch in PatchType.GetMethods()) {
                    Harmony.Unpatch(original, patch);
                }
            }
            IsEnabled = false;
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using AdofaiTweaks.Core.Attributes;
using AdofaiTweaks.Translation;
using HarmonyLib;
using UnityEngine;

namespace AdofaiTweaks.Core;

internal class TweakRunner
{
    internal Tweak Tweak { get; private set; }
    internal RegisterTweakAttribute TweakMetadata { get; private set; }

    private TweakSettings Settings { get; set; }
    private IList<TweakPatch> TweakPatches { get; set; } = new List<TweakPatch>();
    private IList<TweakPatch> ValidTweakPatches { get; set; } = new List<TweakPatch>();
    private readonly Harmony harmony;

    [SyncTweakSettings]
    private static GlobalSettings GlobalSettings { get; set; }

    public TweakRunner(Tweak tweak, TweakSettings settings) {
        Tweak = tweak;
        Settings = settings;
        TweakMetadata = Attribute.GetCustomAttribute(tweak.GetType(), typeof(RegisterTweakAttribute)) as RegisterTweakAttribute;
        harmony = new Harmony("adofai_tweaks." + TweakMetadata.Id);

        foreach (Type type in TweakMetadata.PatchesType.GetNestedTypes(AccessTools.all)) {
            TweakPatchAttribute attr = type.GetCustomAttributes(false).OfType<TweakPatchAttribute>()?.FirstOrDefault();
            if (attr != null) {
                TweakPatch tweakPatch = new TweakPatch(type, attr, harmony);
                TweakPatch duplicatePatch = TweakPatches.FirstOrDefault(p => p.Metadata.PatchId.Equals(attr.PatchId));
                if (duplicatePatch != null) {
                    AdofaiTweaks.Logger.Log($"Patch with the ID of '{duplicatePatch.Metadata.PatchId}' is already registered.");
                } else {
                    if (tweakPatch?.IsValidPatch(true) ?? false) {
                        ValidTweakPatches.Add(tweakPatch);
                    }
                    TweakPatches.Add(tweakPatch);
                }
            }
        }
    }

    private Type[] GetAllNestedTypes(Type type) {
        return GetAllNestedTypes(type.GetNestedTypes(AccessTools.all));
    }

    private Type[] GetAllNestedTypes(Type[] types) {
        List<Type> typeList = new List<Type>(types.ToArray());
        foreach (Type t in types) {
            typeList.Add(GetAllNestedTypes(t));
        }
        return typeList.ToArray();
    }

    private void EnableTweak() {
        Tweak.OnEnable();
        foreach (Type type in GetAllNestedTypes(TweakMetadata.PatchesType)) {
            try { harmony.CreateClassProcessor(type).Patch(); }
            catch (Exception e) { AdofaiTweaks.Logger.Log($"  [WARN] Failed to patch {type.Name}: {e.GetType().Name} - {e.Message}"); }
        }
        foreach (TweakPatch patch in ValidTweakPatches) {
            try { patch.Patch(); } catch (Exception e) { AdofaiTweaks.Logger.Log($"  [WARN] TweakPatch {patch.Metadata.PatchId} failed: {e.Message}"); }
        }
        Tweak.OnPatch();
    }

    private void DisableTweak() {
        Tweak.OnDisable();
        harmony.UnpatchAll(harmony.Id);
        foreach (TweakPatch patch in ValidTweakPatches) {
            patch.Unpatch();
        }
        Tweak.OnUnpatch();
    }

    internal void Start() {
        if (Settings.IsEnabled) EnableTweak();
    }

    internal void Stop() {
        if (Settings.IsEnabled) DisableTweak();
    }

    internal void OnGUI() {
        GUILayout.BeginHorizontal();
        bool newIsExpanded = GUILayout.Toggle(Settings.IsExpanded,
            Settings.IsEnabled ? (Settings.IsExpanded ? "\u25e2" : "\u25b6") : "",
            new GUIStyle() { fixedWidth = 10, normal = new GUIStyleState() { textColor = Color.white }, fontSize = 15, margin = new RectOffset(4, 2, 6, 6) });
        bool newIsEnabled = GUILayout.Toggle(Settings.IsEnabled, Tweak.Name,
            new GUIStyle(GUI.skin.toggle) { fontStyle = GlobalSettings.Language.IsSymbolLanguage() ? FontStyle.Normal : FontStyle.Bold,
                font = (GlobalSettings.Language.IsSymbolLanguage() && TweakAssets.KoreanBoldFont != null) ? TweakAssets.KoreanBoldFont : null, margin = new RectOffset(0, 4, 4, 4) });
        GUILayout.Label("-");
        GUILayout.Label(Tweak.Description, new GUIStyle(GUI.skin.label) { fontStyle = FontStyle.Italic });
        GUILayout.FlexibleSpace();
        GUILayout.EndHorizontal();

        if (newIsEnabled != Settings.IsEnabled) {
            Settings.IsEnabled = newIsEnabled;
            if (newIsEnabled) { EnableTweak(); newIsExpanded = true; } else { DisableTweak(); }
        }

        if (newIsExpanded != Settings.IsExpanded) {
            Settings.IsExpanded = newIsExpanded;
            if (!newIsExpanded) Tweak.OnHideGUI();
        }

        if (Settings.IsExpanded && Settings.IsEnabled) {
            GUILayout.BeginHorizontal();
            GUILayout.Space(24f);
            GUILayout.BeginVertical();
            try { Tweak.OnSettingsGUI(); } catch (Exception e) { AdofaiTweaks.Logger.Log($"  [WARN] OnSettingsGUI for {TweakMetadata.Id} failed: {e.Message}"); }
            GUILayout.EndVertical();
            GUILayout.EndHorizontal();
            GUILayout.Space(12f);
        }
    }

    internal void OnHideGUI() { if (Settings.IsEnabled) Tweak.OnHideGUI(); }
