            Settings.PlanetOpacity2.Tail = Settings.SettingsOpacity2;
            Settings.PlanetOpacity2.Ring = Settings.SettingsOpacity2;
            Settings.SettingsOpacity2 = PlanetOpacitySettings.MIGRATED_VALUE;
