namespace AdofaiTweaks.Tweaks.RestrictGameplay;

/// <summary>
/// Restrict gameplay tweak's gameplay punishment type.
/// </summary>
public enum RestrictGameplayAction
{
    KillPlayer,
    NoRegister,
    InstantRestart,
}

using System.Collections;
using System.Collections.Generic;
using System.Globalization;
using System.Linq;
using System.Reflection;
using AdofaiTweaks.Core;
using AdofaiTweaks.Core.Attributes;
using HarmonyLib;
using JetBrains.Annotations;
using UnityEngine.UI;

namespace AdofaiTweaks.Tweaks.RestrictGameplay;

internal static class RestrictGameplayPatches
{
    [SyncTweakSettings]
    private static RestrictGameplaySettings Settings { get; set; }

    private static readonly MethodInfo ResetCustomLevelMethod =
        AccessTools.Method(typeof(scrController), "ResetCustomLevel");

    private static readonly MethodInfo RestartMethod =
        AccessTools.Method(typeof(scrController), "Restart");

    private static readonly FieldInfo HitErrorMeterAverageAngleField =
        AccessTools.Field(typeof(scrHitErrorMeter), "averageAngle");

    private enum FailReason {
        None,
        Judgment,
        AverageAngle,
    }

    private static string GetCustomFailActionMessage(this FailReason failReason) {
        return failReason switch {
            FailReason.Judgment => Settings.CustomDeathStringForJudgment.Replace(
                "{judgment}",
                TweakStrings.GetRDString("HitMargin." + latestHitMargin)),
            FailReason.AverageAngle => Settings.CustomDeathStringForAverageAngle.Replace(
                "{averageAngle}",
                Settings.AllowedAverageAngleThreshold.ToString(CultureInfo.InvariantCulture)),
            _ => ""
        };
    }

    private static FailReason failActionInvokeReason;
    private static HitMargin latestHitMargin;
    private static bool hideMarginText;
    private static bool shouldFailPlayer;
    private static bool shouldInstantRestart;

    private static scrController Controller => scrController.instance;

    [UsedImplicitly]
    [TweakPatch(
        "RestrictGameplay.IsValidHitWithRestrictions",
        "scrMisc",
        "IsValidHit",
        MinVersion = 80)]
    private static class IsValidHitWithRestrictionsPatch
    {
        [UsedImplicitly]
        public static void Postfix(ref bool __result, HitMargin margin) {
            if (!Controller.gameworld) return;

            var restrictJudgment = (CheckJudgment(margin), FailReason.Judgment);
            var restrictAverageAngle = (CheckAverageAngle(), FailReason.AverageAngle);

            var (restrictAction, failReason) = SelectRestrictAction(restrictJudgment, restrictAverageAngle);
            if (restrictAction == null) return;

            __result = false;

            switch (restrictAction) {
                case RestrictGameplayAction.KillPlayer:
                    latestHitMargin = margin;
                    shouldFailPlayer = true;
                    failActionInvokeReason = failReason;
                    break;
                case RestrictGameplayAction.InstantRestart:
                    shouldInstantRestart = true;
                    shouldFailPlayer = true;
                    failActionInvokeReason = failReason;
                    break;
                case RestrictGameplayAction.NoRegister:
                    break;
            }
        }

        private static RestrictGameplayAction? CheckJudgment(HitMargin margin) {
            if (!Settings.RestrictJudgment) return null;
            if (!Settings.RestrictedJudgments[(int)margin]) return null;
            return Settings.RestrictGameplayActionForJudgment;
        }

        private static RestrictGameplayAction? CheckAverageAngle() {
            if (!Settings.RestrictAverageAngle) return null;
            var errorMeter = Controller.errorMeter;
            float averageAngle;
            if (errorMeter) {
                averageAngle = (float)HitErrorMeterAverageAngleField.GetValue(errorMeter);
            } else {
                averageAngle = 0;
            }
            if (averageAngle >= -Settings.AllowedAverageAngleThreshold &&
                averageAngle <= Settings.AllowedAverageAngleThreshold) return null;
            return Settings.RestrictGameplayActionForAverageAngle;
        }

        private static (RestrictGameplayAction?, FailReason) SelectRestrictAction(params (RestrictGameplayAction?, FailReason)[] actions) {
            return actions.Select(x => x.Item1 switch {
                RestrictGameplayAction.NoRegister => (x, 1),
                RestrictGameplayAction.KillPlayer => (x, 2),
                RestrictGameplayAction.InstantRestart => (x, 3),
                _ => (x, 0),
            }).Aggregate((a, b) => a.Item2 > b.Item2 ? a : b).x;
        }
    }

    [UsedImplicitly]
    [TweakPatch(
        "RestrictGameplay.SwitchChosenInstantRestartTrigger",
        "scrPlanet",
        "SwitchChosen",
        MinVersion = 80)]
    private static class SwitchChosenInstantRestartTriggerPatch
    {
        [UsedImplicitly]
        public static void Postfix() {
            if (!shouldFailPlayer) return;
            shouldFailPlayer = false;

            if (shouldInstantRestart) {
                bool origNoFail = Controller.noFail;
                Controller.noFail = false;
                Controller.instantExplode = true;
                Controller.FailAction();
                Controller.noFail = origNoFail;
            } else {
                Controller.FailAction(true);
                Controller.Fail2Action();
            }
        }
    }

    [UsedImplicitly]
    [TweakPatch(
        "RestrictGameplay.Fail2_UpdateFast",
        "scrController",
        "Fail2_Update",
        MinVersion = 80)]
    private static class Fail2_UpdateFastPatch
    {
        [UsedImplicitly]
        public static bool Prefix(scrController __instance) {
            if (!shouldInstantRestart) return true;

            shouldInstantRestart = false;
            Controller.instantExplode = false;

            if (scnEditor.instance != null) {
                object[] resetParams = AdofaiTweaks.ReleaseNumber >= 110 ? [true] : [];
                __instance.StartCoroutine(
                    (IEnumerator)ResetCustomLevelMethod.Invoke(__instance, resetParams));
            } else {
                object[] resetParams = AdofaiTweaks.ReleaseNumber >= 110 ? [false] : [];
                RestartMethod.Invoke(__instance, resetParams);
            }
            return false;
        }
    }

    [UsedImplicitly]
    [TweakPatch(
        "RestrictGameplay.CountdownShowOverload",
        "scrCountdown",
        "ShowOverload",
        MinVersion = 80)]
    private static class CountdownShowOverloadPatch
    {
        [UsedImplicitly]
        public static void Postfix(scrCountdown __instance, Text ___text) {
            if (failActionInvokeReason != FailReason.None) {
                failActionInvokeReason = FailReason.None;
                ___text.text = failActionInvokeReason.GetCustomFailActionMessage();
            }
        }
    }

    [UsedImplicitly]
    [TweakPatch(
        "RestrictGameplay.ControllerShowHitText",
        "scrHitTextManager",
        "ShowHitText",
        MinVersion = 80)]
    private static class ControllerShowHitTextPatch
    {
        [UsedImplicitly]
        public static bool Prefix() {
            if (hideMarginText) {
                return hideMarginText = false;
            }
            return true;
        }
    }
}

using AdofaiTweaks.Core;

namespace AdofaiTweaks.Tweaks.RestrictGameplay;

/// <summary>
/// Settings for the Restrict Gameplay tweak.
/// </summary>
public class RestrictGameplaySettings : TweakSettings
{
    /// <summary>
    /// Whether to restrict gameplay by judgment.
    /// </summary>
    public bool RestrictJudgment { get; set; }

    /// <summary>
    /// Whether to restrict the judgment. If <c>RestrictGameplay[i]</c> is
    /// <c>true</c>, then punish the player on judgment <c>i</c>.
    /// </summary>
    public bool[] RestrictedJudgments { get; set; }

    /// <summary>
    /// The string to display when the tweak kills the player. If the string
    /// contains <c>{judgment}</c>, it will be replaced by the judgment name
    /// that killed the player.
    /// </summary>
    public string CustomDeathStringForJudgment { get; set; } = "No {judgment}s allowed!";

    /// <summary>
    /// The string to display when the tweak kills the player. If the string
    /// contains <c>{averageAngle}</c>, it will be replaced by player's
    /// <see cref="AllowedAverageAngleThreshold"/> value.
    /// </summary>
    public string CustomDeathStringForAverageAngle { get; set; } = "Average angle left the ±{averageAngle}° range!";

    /// <summary>
    /// An action to restrict gameplay on judgment restriction.
    /// </summary>
    public RestrictGameplayAction RestrictGameplayActionForJudgment { get; set; }

    /// <summary>
    /// An action to restrict gameplay on average angle restriction.
    /// </summary>
    public RestrictGameplayAction RestrictGameplayActionForAverageAngle { get; set; }

    /// <summary>
    /// Whether to restrict the gameplay by average angle of a hit error meter.
    /// </summary>
    public bool RestrictAverageAngle { get; set; }

    /// <summary>
    /// Allowed range of the average angle.
    /// </summary>
    public float AllowedAverageAngleThreshold { get; set; } = 60;
}

using System;
using System.Globalization;
using AdofaiTweaks.Core;
using AdofaiTweaks.Core.Attributes;
using AdofaiTweaks.Strings;
using JetBrains.Annotations;
using UnityEngine;

namespace AdofaiTweaks.Tweaks.RestrictGameplay;

/// <summary>
/// A tweak for punishing the player on certain criteria.
/// </summary>
[UsedImplicitly]
[RegisterTweak(
    id: "restrict_gameplay",
    settingsType: typeof(RestrictGameplaySettings),
    patchesType: typeof(RestrictGameplayPatches))]
internal class RestrictGameplayTweak : Tweak {
    private static readonly HitMargin[] JUDGMENTS_TO_RESTRICT = [
        HitMargin.TooEarly,
        HitMargin.VeryEarly,
        HitMargin.EarlyPerfect,
        HitMargin.Perfect,
        HitMargin.LatePerfect,
        HitMargin.VeryLate,
        HitMargin.TooLate
    ];

    private static readonly RestrictGameplayAction[] RESTRICT_ACTIONS = [
        RestrictGameplayAction.KillPlayer,
        RestrictGameplayAction.InstantRestart,
        RestrictGameplayAction.NoRegister
    ];

    /// <inheritdoc/>
    public override string Name =>
        TweakStrings.Get(TranslationKeys.RestrictGameplay.NAME);

    /// <inheritdoc/>
    public override string Description =>
        TweakStrings.Get(TranslationKeys.RestrictGameplay.DESCRIPTION);

    [SyncTweakSettings]
    private RestrictGameplaySettings Settings { get; set; }

    /// <inheritdoc/>
    public override void OnSettingsGUI() {
        if (Settings.RestrictJudgment = GUILayout.Toggle(
            Settings.RestrictJudgment,
            TweakStrings.Get(TranslationKeys.RestrictGameplay.RESTRICT_JUDGMENT))) {
            MoreGUILayout.BeginIndent();

            // Select judgment to restrict
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.SELECT_JUDGMENT));
            MoreGUILayout.BeginIndent();
            foreach (var hitMargin in JUDGMENTS_TO_RESTRICT) {
                Settings.RestrictedJudgments[(int)hitMargin] = GUILayout.Toggle(
                    Settings.RestrictedJudgments[(int)hitMargin],
                    TweakStrings.Get(
                        TranslationKeys.RestrictGameplay.RESTRICT_JUDGMENT_ITEM,
                        [TweakStrings.GetRDString($"HitMargin.{hitMargin}")]));
            }
            MoreGUILayout.EndIndent();

            // Select penalty for this restriction
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.SELECT_PENALTY));
            foreach (var action in RESTRICT_ACTIONS) {
                if (GUILayout.Toggle(
                        Settings.RestrictGameplayActionForJudgment == action,
                        TweakStrings.Get($"RESTRICT_GAMEPLAY_I_RESTRICT_ACTION.{action}"))
                    && Settings.RestrictGameplayActionForJudgment != action) {
                    Settings.RestrictGameplayActionForJudgment = action;
                }
            }

            // Custom death message for this restriction
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.CUSTOM_DEATH_JUDGMENT));
            Settings.CustomDeathStringForJudgment = GUILayout.TextField(Settings.CustomDeathStringForJudgment);

            MoreGUILayout.EndIndent();
        }

        if (Settings.RestrictAverageAngle = GUILayout.Toggle(
            Settings.RestrictAverageAngle,
            TweakStrings.Get(TranslationKeys.RestrictGameplay.RESTRICT_AVERAGE_ANGLE))) {
            MoreGUILayout.BeginIndent();

            // Set threshold for average angle
            GUILayout.BeginHorizontal();
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.RESTRICT_AVERAGE_ANGLE_THRESHOLD));

            GUILayout.Label(" ±");
            var textFieldValue =
                Convert.ToSingle(
                    GUILayout.TextField(Settings.AllowedAverageAngleThreshold.ToString(CultureInfo.InvariantCulture)));
            GUILayout.Label("°");

            if (textFieldValue > 0) {
                Settings.AllowedAverageAngleThreshold = textFieldValue;
            }
            GUILayout.EndHorizontal();

            // Select penalty for this restriction
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.SELECT_PENALTY));
            foreach (var action in RESTRICT_ACTIONS) {
                if (GUILayout.Toggle(
                        Settings.RestrictGameplayActionForAverageAngle == action,
                        TweakStrings.Get($"RESTRICT_GAMEPLAY_I_RESTRICT_ACTION.{action}"))
                    && Settings.RestrictGameplayActionForAverageAngle != action) {
                    Settings.RestrictGameplayActionForAverageAngle = action;
                }
            }

            // Custom death message for this restriction
            GUILayout.Label(TweakStrings.Get(TranslationKeys.RestrictGameplay.CUSTOM_DEATH_AVERAGE_ANGLE));
            Settings.CustomDeathStringForAverageAngle = GUILayout.TextField(Settings.CustomDeathStringForAverageAngle);

            MoreGUILayout.EndIndent();
        }
    }

    /// <inheritdoc/>
    public override void OnEnable() {
        int numJudgmentTypes = Enum.GetValues(typeof(HitMargin)).Length;
        if (Settings.RestrictedJudgments == null) {
            Settings.RestrictedJudgments = new bool[numJudgmentTypes];
        } else if (Settings.RestrictedJudgments.Length != numJudgmentTypes) {
            // Judgments were added/removed, migrate to new settings
            bool[] migratedJudgments = new bool[numJudgmentTypes];
            int len = Math.Min(numJudgmentTypes, Settings.RestrictedJudgments.Length);
            for (int i = 0; i < len; i++) {
                migratedJudgments[i] = Settings.RestrictedJudgments[i];
            }
            Settings.RestrictedJudgments = migratedJudgments;
        }
    }
}

using System.Collections.Generic;
using System.Collections.ObjectModel;
using System.Linq;

namespace AdofaiTweaks.Utils;

public static class PathDataUtils {
    private static readonly ReadOnlyDictionary<char, int> PathTable = new (new Dictionary<char, int> {
            { 'W', 195 }, { 'H', 210 }, { 'Q', 225 }, { 'G', 240 }, { 'q', 255 },
            { 'U', 270 }, { 'o', 285 }, { 'T', 300 }, { 'E', 315 }, { 'J', 330 },
            { 'p', 345 }, { 'R', 0 },   { 'A', 15 },  { 'M', 30 },  { 'C', 45 },
            { 'B', 60 },  { 'Y', 75 },  { 'D', 90 },  { 'V', 105 }, { 'F', 120 },
            { 'Z', 135 }, { 'N', 150 }, { 'x', 165 }, { 'L', 180 },
    });

    public static char GetRotatedPath(char pathCode, bool clockwise) {
        if (!PathTable.TryGetValue(pathCode, out var angle)) {
            return pathCode;
        }
        angle = (angle + (clockwise ? 15 : -15) + 360) % 360;
        return PathTable.FirstOrDefault(p => p.Value == angle).Key;
    }
}

using JetBrains.Annotations;

namespace AdofaiTweaks.Utils;

[UsedImplicitly(ImplicitUseTargetFlags.WithMembers)]
public static class PlanetComparison {
    public static bool IsRedPlanet(this PlanetRenderer planet) => planet && planet == PlanetGetter.RedPlanet?.planetRenderer;
    public static bool IsBluePlanet(this PlanetRenderer planet) => planet && planet == PlanetGetter.BluePlanet?.planetRenderer;
    public static bool IsGreenPlanet(this PlanetRenderer planet) => planet && planet == PlanetGetter.GreenPlanet?.planetRenderer;
    public static bool IsRedPlanetLegacy(this scrPlanet planet) => planet && planet == PlanetGetter.RedPlanet;
    public static bool IsBluePlanetLegacy(this scrPlanet planet) => planet && planet == PlanetGetter.BluePlanet;
    public static bool IsGreenPlanetLegacy(this scrPlanet planet) => planet && planet == PlanetGetter.GreenPlanet;
    public static bool IsFake(PlanetRenderer planet) => !planet || (!planet.IsRedPlanet() && !planet.IsBluePlanet() && !planet.IsGreenPlanet());
    public static bool IsFakeLegacy(scrPlanet planet) => !planet || (!planet.IsRedPlanetLegacy() && !planet.IsBluePlanetLegacy() && !planet.IsGreenPlanetLegacy());
}

using System.Reflection;
using HarmonyLib;

namespace AdofaiTweaks.Utils;

public static class PlanetGetter {
    private enum PlanetType { Red, Blue, Green }

    private static readonly FieldInfo LegacyRedPlanetField = AccessTools.Field(typeof(scrController), "redPlanet");
    private static readonly FieldInfo LegacyBluePlanetField = AccessTools.Field(typeof(scrController), "bluePlanet");
    private static readonly FieldInfo LegacyGreenPlanetField = AccessTools.Field(typeof(scrController), "greenPlanet");

    public static scrPlanet RedPlanet {
        get {
            return AdofaiTweaks.ReleaseNumber switch {
                <= 127 => scrController.instance == null ? null : (scrPlanet)LegacyRedPlanetField.GetValue(scrController.instance),
                _ => GetNewPlanet(PlanetType.Red)
            };
        }
    }

    public static scrPlanet BluePlanet {
        get {
            return AdofaiTweaks.ReleaseNumber switch {
                <= 127 => scrController.instance == null ? null : (scrPlanet)LegacyBluePlanetField.GetValue(scrController.instance),
                _ => GetNewPlanet(PlanetType.Blue)
            };
        }
    }

    public static scrPlanet GreenPlanet {
        get {
            return AdofaiTweaks.ReleaseNumber switch {
                <= 127 => scrController.instance == null ? null : (scrPlanet)LegacyGreenPlanetField?.GetValue(scrController.instance),
                _ => GetNewPlanet(PlanetType.Green)
            };
        }
    }

    private static scrPlanet GetNewPlanet(PlanetType planet) {
        return planet switch {
            PlanetType.Red => scrController.instance?.planetRed,
            PlanetType.Blue => scrController.instance?.planetBlue,
            PlanetType.Green => scrController.instance?.planetGreen,
            _ => null
        };
    }
}

using System.Reflection;
using HarmonyLib;

namespace AdofaiTweaks.Utils;

public static class SteamIntegrationChecker {
    public static bool Check() {
        if (AdofaiTweaks.ReleaseNumber < 131) {
            return OldSteamIntegrationCheck();
        }
        return SteamIntegration.initialized;
    }

    private static readonly FieldInfo SteamIntegrationInstanceField =
        AccessTools.Field(typeof(SteamIntegration), "Instance");
    private static readonly FieldInfo SteamIntegrationInitializedField =
        AccessTools.Field(typeof(SteamIntegration), "initialized");

    private static bool OldSteamIntegrationCheck() {
        var integration = (SteamIntegration)SteamIntegrationInstanceField.GetValue(null);
        if (integration == null) return false;
        return (bool)SteamIntegrationInitializedField.GetValue(integration);
    }
}
